#!/bin/bash
sed -i '/import { Sparkles } from "lucide-react";/a import { Bot, LogIn } from "lucide-react";\nimport { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";\nimport { Button } from "@/components/ui/button";' client/src/components/AppShell.tsx

sed -i '/{\/\* Aura indicator \*\/}/i \          <div className="ml-auto mr-4">\n            <Dialog>\n              <DialogTrigger asChild>\n                <Button variant="ghost" size="sm" className="gap-2">\n                  <LogIn className="h-4 w-4" />\n                  Sign In\n                </Button>\n              </DialogTrigger>\n              <DialogContent className="sm:max-w-md">\n                <DialogHeader>\n                  <DialogTitle>Connect your account</DialogTitle>\n                  <DialogDescription>\n                    Sign in with your preferred platform to access Stix Magic.\n                  </DialogDescription>\n                </DialogHeader>\n                <div className="flex flex-col gap-4 py-4">\n                  <Button className="w-full gap-2" size="lg" onClick={() => window.location.href = "/api/auth/zoom"}>\n                    Sign in with Zoom\n                  </Button>\n                  <Button className="w-full gap-2" variant="outline" size="lg" onClick={() => window.location.href = "/api/auth/telegram"}>\n                    <Bot className="h-4 w-4" />\n                    Sign in with Telegram\n                  </Button>\n                </div>\n              </DialogContent>\n            </Dialog>\n          </div>' client/src/components/AppShell.tsx

sed -i 's/<div className="ml-auto">/<div className="">/' client/src/components/AppShell.tsx
